Rules.InvariantScript:
// reset controls
Reset(tog_MaterialColors_Components__CustomValue);
Reset(gal_MaterialColors_Selection);
Reset(txt_MaterialColors_Components__CustomValue);
// clear variables
UpdateContext(
    {
        locShowSaveButton: false,
        locCurrentMaterialItem: Blank(),
        locGUIDJobMaterialItem: Blank(),
        locMaterialColorSelected: Blank(),
        locMaterialColorIsCustomValue: Blank(),
        locMaterialColorIsPredefinedOptions: Blank()
    }
);
// clear collections
ClearCollect(
    colMaterialItemColors,
    {
        Value: "",
        Attribute: "Color"
    }
);

// select the material color and show the save button
UpdateContext(
    {
        locMaterialColorSelected: ThisItem.Value,
        locShowSaveButton: true

    }
);
// write the selection to the materials colors collection
Patch(
    colMaterialItemColors,
    LookUp(
        colMaterialItemColors,
        Attribute = "Color"
    ),
    {
        Attribute: "Color",
        ID: ThisItem.ID,
        Value: ThisItem.Value
    }
);
// reset controls
Reset(gal_MaterialColors__Selected);

With(
    {
        varType: "colCdsJobMaterialItems",
        varRecordRef: locGUIDJobMaterialItem
    },
// update color in job materials record 
    Patch(
        colCdsJobMaterialItems,
        LookUp(colCdsJobMaterialItems, 'Job Material Item'=varRecordRef),
        {
            Color: LookUp(colMaterialItemColors, Attribute="Color", locMaterialColorSelected)
        }
    );
    If(
        IsBlank(
            LookUp(
                colAUDRecords,
                Type = varType
                And RecordRef = varRecordRef
            )
        ),
        Collect(
            colAUDRecords,
            {
                Type: varType,
                RecordRef: varRecordRef,
                Job: gblRecordJobCurrent.Job,
                Operation: "U"
            }
        )
    )
);
// save local data
IfError( // This line of code is added to hide the errors
If(
    gblAppLoadOffline,
    SaveData(
        colAUDRecords,
        "localAUDRecords"
    );
    SaveData(
        colCdsJobMaterialItems,
        "localCdsJobMaterialItems"
    )
)
,Blank())  // This line of code is added to hide the errors
;
// leave the screen and reset
Reset(gal_MaterialColors__Selected);
Reset(gal_MaterialColors_Selection);
// next screen
Navigate(
    'Materials Screen',
    BorderStyle.None
);
